@app.route('/api/documents', methods=['POST'])
def create_document():
    """Create a new document in the CMS."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'No data provided'}), 400

    required_fields = ['title', 'content', 'author_id']
    for field in required_fields:
        if field not in data:
            return jsonify({'error': f'Missing required field: {field}'}), 400

    author_oid = object_id_str(data['author_id'])
    if not author_oid:
        return jsonify({'error': 'Invalid author ID'}), 400

    # Verify author exists
    author = users_collection.find_one({'_id': author_oid, 'is_active': True})
    if not author:
        return jsonify({'error': 'Author not found or inactive'}), 404

    document = {
        'title': data['title'],
        'content': data['content'],
        'author_id': author_oid,
        'author_name': author['full_name'],
        'slug': data.get('slug', data['title'].lower().replace(' ', '-')),
        'status': data.get('status', 'draft'),  # draft, published, archived
        'category': data.get('category', 'uncategorized'),
        'tags': data.get('tags', []),
        'metadata': data.get('metadata', {}),
        'featured_image': data.get('featured_image', ''),
        'excerpt': data.get('excerpt', ''),
        'word_count': len(data['content'].split()),
        'views': 0,
        'likes': 0,
        'comments': [],
        'revision_history': [{
            'revision': 1,
            'content': data['content'],
            'edited_at': datetime.utcnow(),
            'edited_by': author_oid
        }],
        'created_at': datetime.utcnow(),
        'updated_at': datetime.utcnow(),
        'published_at': datetime.utcnow() if data.get('status') == 'published' else None
    }

    try:
        result = documents_collection.insert_one(document)
        document['_id'] = result.inserted_id

        # Update user's document count
        users_collection.update_one({'_id': author_oid}, {'$inc': {'document_count': 1}})

        return jsonify({'message': 'Document created successfully', 'document': parse_json(document)}), 201
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/documents', methods=['GET'])
def get_documents():
    """Get documents with advanced querying."""
    # Query parameters
    status = request.args.get('status')
    category = request.args.get('category')
    author_id = request.args.get('author_id')
    tag = request.args.get('tag')
    search = request.args.get('search')
    sort_by = request.args.get('sort_by', 'created_at')
    sort_order = request.args.get('sort_order', 'desc')
    page = int(request.args.get('page', 1))
    per_page = int(request.args.get('per_page', 20))
    date_from = request.args.get('date_from')
    date_to = request.args.get('date_to')

    query = {}

    if status:
        query['status'] = status
    if category:
        query['category'] = category
    if author_id:
        oid = object_id_str(author_id)
        if oid:
            query['author_id'] = oid
    if tag:
        query['tags'] = {'$in': [tag]}
    if search:
        query['$text'] = {'$search': search}
    if date_from or date_to:
        date_filter = {}
        if date_from:
            date_filter['$gte'] = datetime.fromisoformat(date_from)
        if date_to:
            date_filter['$lte'] = datetime.fromisoformat(date_to)
        query['created_at'] = date_filter

    sort_direction = DESCENDING if sort_order == 'desc' else ASCENDING
    skip = (page - 1) * per_page

    # Exclude content and revision_history for listing
    projection = {
        'content': 0,
        'revision_history': 0,
        'comments': 0
    }

    documents = list(
        documents_collection.find(query, projection)
        .skip(skip)
        .limit(per_page)
        .sort(sort_by, sort_direction)
    )
    total = documents_collection.count_documents(query)

    return jsonify({
        'documents': parse_json(documents),
        'total': total,
        'page': page,
        'per_page': per_page,
        'total_pages': (total + per_page - 1) // per_page
    }), 200


@app.route('/api/documents/<doc_id>', methods=['GET'])
def get_document(doc_id):
    """Get a specific document with full content."""
    oid = object_id_str(doc_id)
    if not oid:
        return jsonify({'error': 'Invalid document ID'}), 400

    document = documents_collection.find_one({'_id': oid})
    if not document:
        return jsonify({'error': 'Document not found'}), 404

    # Increment view count
    documents_collection.update_one({'_id': oid}, {'$inc': {'views': 1}})
    document['views'] += 1

    return jsonify({'document': parse_json(document)}), 200


@app.route('/api/documents/<doc_id>', methods=['PUT'])
def update_document(doc_id):
    """Update a document with revision tracking."""
    oid = object_id_str(doc_id)
    if not oid:
        return jsonify({'error': 'Invalid document ID'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'No data provided'}), 400

    existing = documents_collection.find_one({'_id': oid})
    if not existing:
        return jsonify({'error': 'Document not found'}), 404

    allowed_fields = ['title', 'content', 'status', 'category', 'tags', 'metadata',
                      'featured_image', 'excerpt', 'slug']
    update_data = {k: v for k, v in data.items() if k in allowed_fields}
    update_data['updated_at'] = datetime.utcnow()

    if 'content' in update_data:
        update_data['word_count'] = len(update_data['content'].split())
        # Add revision
        current_revisions = existing.get('revision_history', [])
        new_revision = {
            'revision': len(current_revisions) + 1,
            'content': update_data['content'],
            'edited_at': datetime.utcnow(),
            'edited_by': existing['author_id']
        }
        documents_collection.update_one(
            {'_id': oid},
            {'$push': {'revision_history': new_revision}}
        )

    if update_data.get('status') == 'published' and existing.get('status') != 'published':
        update_data['published_at'] = datetime.utcnow()

    result = documents_collection.update_one({'_id': oid}, {'$set': update_data})

    updated_doc = documents_collection.find_one({'_id': oid})
    return jsonify({'message': 'Document updated successfully', 'document': parse_json(updated_doc)}), 200


@app.route('/api/documents/<doc_id>', methods=['DELETE'])
def delete_document(doc_id):
    """Delete a document."""
    oid = object_id_str(doc_id)
    if not oid:
        return jsonify({'error': 'Invalid document ID'}), 400

    document = documents_collection.find_one({'_id': oid})
    if not document:
        return jsonify({'error': 'Document not found'}), 404

    documents_collection.delete_one({'_id': oid})

    # Decrement user's document count
    users_collection.update_one(
        {'_id': document['author_id']},
        {'$inc': {'document_count': -1}}
    )

    return jsonify({'message': 'Document deleted successfully'}), 200


@app.route('/api/documents/<doc_id>/like', methods=['POST'])
def like_document(doc_id):
    """Like a document."""
    oid = object_id_str(doc_id)
    if not oid:
        return jsonify({'error': 'Invalid document ID'}), 400

    result = documents_collection.update_one({'_id': oid}, {'$inc': {'likes': 1}})
    if result.matched_count == 0:
        return jsonify({'error': 'Document not found'}), 404

    return jsonify({'message': 'Document liked'}), 200


@app.route('/api/documents/<doc_id>/comments', methods=['POST'])
def add_comment(doc_id):
    """Add a comment to a document."""
    oid = object_id_str(doc_id)
    if not oid:
        return jsonify({'error': 'Invalid document ID'}), 400

    data = request.get_json()
    if not data or 'user_id' not in data or 'text' not in data:
        return jsonify({'error': 'user_id and text are required'}), 400

    user_oid = object_id_str(data['user_id'])
    if not user_oid:
        return jsonify({'error': 'Invalid user ID'}), 400

    user = users_collection.find_one({'_id': user_oid})
    if not user:
        return jsonify({'error': 'User not found'}), 404

    comment = {
        'comment_id': ObjectId(),
        'user_id': user_oid,
        'user_name': user['full_name'],
        'text': data['text'],
        'created_at': datetime.utcnow()
    }

    result = documents_collection.update_one(
        {'_id': oid},
        {'$push': {'comments': comment}}
    )
    if result.matched_count == 0:
        return jsonify({'error': 'Document not found'}), 404

    return jsonify({'message': 'Comment added', 'comment': parse_json(comment)}), 201


